import{_ as l,o as i,c as a,ai as o}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"Docker 实战学习技术（知识框架 -> 工程实践）","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/devops/docker.md","filePath":"tech-system/devops/docker.md"}'),s={name:"tech-system/devops/docker.md"};function r(d,e,c,t,h,n){return i(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="docker-实战学习技术-知识框架-工程实践" tabindex="-1">Docker 实战学习技术（知识框架 -&gt; 工程实践） <a class="header-anchor" href="#docker-实战学习技术-知识框架-工程实践" aria-label="Permalink to “Docker 实战学习技术（知识框架 -&gt; 工程实践）”">​</a></h1><p>Docker 是容器化技术：把应用及其运行环境依赖打包成轻量、可移植的单元。学习 Docker 的关键不是“记命令”，而是建立一套清晰的模型：镜像是模板，容器是运行实例；网络与数据是容器世界里“如何互联与如何保留”的规则。</p><hr><h2 id="_1-docker-核心概念-知识框架" tabindex="-1">1. Docker 核心概念（知识框架） <a class="header-anchor" href="#_1-docker-核心概念-知识框架" aria-label="Permalink to “1. Docker 核心概念（知识框架）”">​</a></h2><h3 id="_1-1-镜像-image" tabindex="-1">1.1 镜像（Image） <a class="header-anchor" href="#_1-1-镜像-image" aria-label="Permalink to “1.1 镜像（Image）”">​</a></h3><ul><li>镜像可以理解为“应用 + 依赖”的<strong>只读模板/快照</strong>。</li><li>同一个镜像可以被创建出多个容器实例，每个容器运行时拥有自己的可写层。</li></ul><p>常见做法：</p><ul><li>为镜像打标签（<code>tag</code>），例如 <code>myapp:dev</code>、<code>myapp:1.0.0</code></li><li>通过 Dockerfile 构建镜像（<code>docker build</code>）</li></ul><h3 id="_1-2-容器-container" tabindex="-1">1.2 容器（Container） <a class="header-anchor" href="#_1-2-容器-container" aria-label="Permalink to “1.2 容器（Container）”">​</a></h3><ul><li>容器是镜像的<strong>运行实例</strong>。</li><li>容器具有隔离的文件系统、进程空间和网络环境。</li><li>容器可读写（相对于镜像的只读模板），写入内容通常落在容器的可写层。</li></ul><p>容器生命周期（理解即可）：</p><ul><li>创建 -&gt; 启动 -&gt; 运行 -&gt; 停止 -&gt; 删除（可复用或重建）</li></ul><h3 id="_1-3-仓库-registry" tabindex="-1">1.3 仓库（Registry） <a class="header-anchor" href="#_1-3-仓库-registry" aria-label="Permalink to “1.3 仓库（Registry）”">​</a></h3><ul><li>仓库是镜像的存储与分发位置。</li><li>常见选择： <ul><li>Docker Hub（公共镜像）</li><li>私有 Registry（团队/企业内部镜像）</li></ul></li></ul><p>典型流程：</p><ul><li>拉取镜像：<code>docker pull</code></li><li>推送镜像：<code>docker push</code></li></ul><h3 id="_1-4-dockerfile" tabindex="-1">1.4 Dockerfile <a class="header-anchor" href="#_1-4-dockerfile" aria-label="Permalink to “1.4 Dockerfile”">​</a></h3><ul><li>Dockerfile 是“构建镜像的脚本/指令集”。</li><li>Dockerfile 会被构建成一系列层（layer），最终得到镜像。</li></ul><p>Dockerfile 常用指令（入门必须会）：</p><ul><li><code>FROM</code>：基础镜像</li><li><code>WORKDIR</code>：工作目录</li><li><code>COPY</code>：拷贝文件到镜像</li><li><code>RUN</code>：构建时执行命令</li><li><code>EXPOSE</code>：声明容器内部监听端口（不等于宿主机映射端口）</li><li><code>CMD</code> / <code>ENTRYPOINT</code>：容器启动命令</li><li><code>ENV</code>：构建/运行环境变量</li></ul><h3 id="_1-5-volumes-数据卷" tabindex="-1">1.5 Volumes（数据卷） <a class="header-anchor" href="#_1-5-volumes-数据卷" aria-label="Permalink to “1.5 Volumes（数据卷）”">​</a></h3><ul><li>容器的可写层适合运行时临时文件，但对于关键业务数据需要持久化。</li><li>Volume 提供“跨容器生命周期”的数据存储能力。</li></ul><p>常见用途：</p><ul><li>数据库（MySQL/PostgreSQL）数据持久化</li><li>上传文件/用户生成内容持久化</li></ul><h3 id="_1-6-network-网络" tabindex="-1">1.6 Network（网络） <a class="header-anchor" href="#_1-6-network-网络" aria-label="Permalink to “1.6 Network（网络）”">​</a></h3><ul><li>Docker 通过网络能力让容器与容器、宿主机之间实现通信。</li><li>常见两类访问方式： <ul><li>从宿主机访问容器：端口映射（<code>-p host:container</code> 或 Compose 的 <code>ports</code>）</li><li>容器之间互访：使用网络与服务名（Compose 通常会提供更顺滑的服务发现体验）</li></ul></li></ul><hr><h2 id="_2-docker-操作基础-命令模型" tabindex="-1">2. Docker 操作基础（命令模型） <a class="header-anchor" href="#_2-docker-操作基础-命令模型" aria-label="Permalink to “2. Docker 操作基础（命令模型）”">​</a></h2><h3 id="_2-1-容器管理命令" tabindex="-1">2.1 容器管理命令 <a class="header-anchor" href="#_2-1-容器管理命令" aria-label="Permalink to “2.1 容器管理命令”">​</a></h3><p>典型命令：</p><ul><li>运行：<code>docker run</code></li><li>查看运行中：<code>docker ps</code></li><li>查看所有（含停止）：<code>docker ps -a</code></li><li>停止：<code>docker stop</code></li><li>删除：<code>docker rm</code></li><li>进入容器执行命令：<code>docker exec -it &lt;container&gt; &lt;cmd&gt;</code></li><li>查看日志：<code>docker logs &lt;container&gt;</code></li></ul><p>快速示例（nginx + 端口映射）：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:80</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:alpine</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_2-2-镜像管理命令" tabindex="-1">2.2 镜像管理命令 <a class="header-anchor" href="#_2-2-镜像管理命令" aria-label="Permalink to “2.2 镜像管理命令”">​</a></h3><p>典型命令：</p><ul><li>构建：<code>docker build</code></li><li>拉取：<code>docker pull</code></li><li>推送：<code>docker push</code></li><li>镜像列表：<code>docker images</code></li><li>给镜像打标签：<code>docker tag</code></li></ul><p>快速示例（构建镜像）：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp:dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> images</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-3-日志与监控-运维视角" tabindex="-1">2.3 日志与监控（运维视角） <a class="header-anchor" href="#_2-3-日志与监控-运维视角" aria-label="Permalink to “2.3 日志与监控（运维视角）”">​</a></h3><ul><li>日志：<code>docker logs</code>（排查启动失败/运行报错最常用）</li><li>资源占用：<code>docker stats</code>（CPU/内存/网络的快速观察）</li></ul><p>建议实践：</p><ul><li>服务尽量将关键日志输出到标准输出（stdout/stderr），便于 <code>docker logs</code> 或日志采集平台抓取。</li></ul><hr><h2 id="_3-docker-高级特性-工程化能力" tabindex="-1">3. Docker 高级特性（工程化能力） <a class="header-anchor" href="#_3-docker-高级特性-工程化能力" aria-label="Permalink to “3. Docker 高级特性（工程化能力）”">​</a></h2><h3 id="_3-1-docker-compose-多容器编排" tabindex="-1">3.1 Docker Compose（多容器编排） <a class="header-anchor" href="#_3-1-docker-compose-多容器编排" aria-label="Permalink to “3.1 Docker Compose（多容器编排）”">​</a></h3><ul><li>Compose 用一个声明文件（<code>docker-compose.yml</code> 或 <code>compose.yaml</code>）管理多个服务。</li><li>你可以在一套配置中定义： <ul><li>服务镜像/构建方式</li><li>端口映射</li><li>环境变量</li><li>数据卷（Volume）</li><li>网络（可选）</li></ul></li></ul><p>常见目标：</p><ul><li>一条命令启动整套系统（比如前端 + 后端 + 数据库）</li><li>可复现环境（便于团队协作与交付）</li></ul><h3 id="_3-2-网络模式-理解差异" tabindex="-1">3.2 网络模式（理解差异） <a class="header-anchor" href="#_3-2-网络模式-理解差异" aria-label="Permalink to “3.2 网络模式（理解差异）”">​</a></h3><p>常见网络模式（概念级理解即可）：</p><ul><li><code>bridge</code>：默认模式，适合单机互联</li><li><code>host</code>：与宿主机共享网络栈（端口/隔离更“直接”，需要谨慎）</li><li><code>overlay</code>：跨主机网络（偏集群场景，例如 Swarm）</li></ul><blockquote><p>建议入门阶段：优先使用默认网络 + Compose 网络；等 Compose 稳定后再理解高级模式。</p></blockquote><h3 id="_3-3-数据管理-volume-bind-mount-tmpfs" tabindex="-1">3.3 数据管理（volume / bind mount / tmpfs） <a class="header-anchor" href="#_3-3-数据管理-volume-bind-mount-tmpfs" aria-label="Permalink to “3.3 数据管理（volume / bind mount / tmpfs）”">​</a></h3><ul><li><code>volume</code>：Docker 管理的数据卷（更适合长期持久化）</li><li><code>bind mount</code>：把宿主机目录挂载进容器（常用于开发环境热更新）</li><li><code>tmpfs</code>：临时内存文件系统（适合不需要落盘的数据）</li></ul><p>工程选择原则：</p><ul><li>生产/持久数据倾向 <code>volume</code></li><li>开发联调倾向 <code>bind mount</code></li><li>临时且可丢数据倾向 <code>tmpfs</code></li></ul><h3 id="_3-4-多阶段构建-multi-stage-build" tabindex="-1">3.4 多阶段构建（Multi-stage build） <a class="header-anchor" href="#_3-4-多阶段构建-multi-stage-build" aria-label="Permalink to “3.4 多阶段构建（Multi-stage build）”">​</a></h3><ul><li>核心思想：构建阶段使用完整工具链，运行阶段只保留必要产物。</li><li>结果：最终镜像更小、攻击面更低、依赖更可控。</li></ul><p>典型结构：</p><ul><li><code>builder</code> 阶段：编译/打包</li><li><code>runtime</code> 阶段：拷贝构建产物并运行</li></ul><h3 id="_3-5-镜像优化-缓存-体积" tabindex="-1">3.5 镜像优化（缓存 + 体积） <a class="header-anchor" href="#_3-5-镜像优化-缓存-体积" aria-label="Permalink to “3.5 镜像优化（缓存 + 体积）”">​</a></h3><p>优化点（入门必须掌握）：</p><ul><li>利用构建缓存（layer cache）：让“不变的步骤”尽量排在前面</li><li>使用 <code>.dockerignore</code>：避免把无关大文件（如 <code>node_modules</code>、构建产物）送进构建上下文</li><li>分层原则：把依赖安装与业务代码拷贝分开，降低缓存失效频率</li></ul><p>收益：</p><ul><li>构建更快</li><li>镜像体积更小</li><li>更容易在 CI/CD 中稳定复现</li></ul><h3 id="_3-6-健康检查与排错-healthcheck-logs" tabindex="-1">3.6 健康检查与排错（Healthcheck + Logs） <a class="header-anchor" href="#_3-6-健康检查与排错-healthcheck-logs" aria-label="Permalink to “3.6 健康检查与排错（Healthcheck + Logs）”">​</a></h3><ul><li><code>healthcheck</code> 表示“服务是否可用”，不等于“容器是否在运行”。</li><li>搭配日志/状态信息可以快速定位： <ul><li>端口监听失败</li><li>依赖服务不可达</li><li>配置/环境变量错误</li></ul></li></ul><hr><h2 id="_4-docker-与-devops-工程落地" tabindex="-1">4. Docker 与 DevOps（工程落地） <a class="header-anchor" href="#_4-docker-与-devops-工程落地" aria-label="Permalink to “4. Docker 与 DevOps（工程落地）”">​</a></h2><h3 id="_4-1-容器化部署-ci-cd-思路" tabindex="-1">4.1 容器化部署（CI/CD 思路） <a class="header-anchor" href="#_4-1-容器化部署-ci-cd-思路" aria-label="Permalink to “4.1 容器化部署（CI/CD 思路）”">​</a></h3><p>典型流水线（概念级）：</p><ol><li>代码提交（Git）</li><li>CI 构建镜像（<code>docker build</code>）</li><li>（可选）运行测试/质量检查</li><li>推送镜像到 Registry（<code>docker push</code>）</li><li>部署环境拉取镜像并启动（<code>docker pull</code> + <code>docker run</code> 或 Compose）</li></ol><p>关键能力点：</p><ul><li>镜像可复现（同一提交 -&gt; 同样构建产物）</li><li>环境配置可控（环境变量/配置文件/密钥管理）</li><li>部署可回滚（镜像版本化）</li></ul><p>常用工具链：</p><ul><li>CI：Jenkins / GitHub Actions / GitLab CI</li><li>构建分发：Docker Hub 或私有 Registry</li><li>部署：服务器上的 Docker/Compose，或进入集群平台</li></ul><h3 id="_4-2-kubernetes-入门-与-compose-的关系" tabindex="-1">4.2 Kubernetes 入门（与 Compose 的关系） <a class="header-anchor" href="#_4-2-kubernetes-入门-与-compose-的关系" aria-label="Permalink to “4.2 Kubernetes 入门（与 Compose 的关系）”">​</a></h3><ul><li>Docker 更偏“容器运行与镜像构建”。</li><li>Kubernetes 更偏“集群调度与编排”（把容器作为基础单元进行统一管理）。</li></ul><p>学习建议：</p><ul><li>先把 Compose 项目跑稳定（容器间通信、卷、日志都要理解）</li><li>再学习 Kubernetes 的 Pod/Service/Deployment 等概念，迁移成本更低</li></ul><hr><h2 id="_5-建议的学习路径-技术体系下的-阶段化验收" tabindex="-1">5. 建议的学习路径（技术体系下的“阶段化验收”） <a class="header-anchor" href="#_5-建议的学习路径-技术体系下的-阶段化验收" aria-label="Permalink to “5. 建议的学习路径（技术体系下的“阶段化验收”）”">​</a></h2><p>你可以把本页当作“知识框架”，配合阶段化验收，形成可落地的能力：</p><ol><li>Stage 1：容器入门 <ul><li>能用 <code>docker run</code> 启动常见镜像并排查启动问题</li><li>能理解端口映射与日志定位</li></ul></li><li>Stage 2：Dockerfile 构建镜像 <ul><li>能编写最小 Dockerfile 并完成构建-运行闭环</li></ul></li><li>Stage 3：数据与网络 <ul><li>能使用 Volume 持久化数据</li><li>能通过 Compose 网络让服务互相通信</li></ul></li><li>Stage 4：Compose 与交付 <ul><li>能用 Compose 编排多服务，并输出可复现的 README</li></ul></li><li>Stage 5：镜像优化 <ul><li>能使用 <code>.dockerignore</code> 与 multi-stage build 做镜像体积/构建速度优化</li></ul></li><li>Stage 6：CI/CD（可选但推荐） <ul><li>能在 CI 中构建并推送镜像，至少完成镜像流水线自动化</li></ul></li></ol><hr><h2 id="_6-常见排错速查-把问题定位到-哪一层" tabindex="-1">6. 常见排错速查（把问题定位到“哪一层”） <a class="header-anchor" href="#_6-常见排错速查-把问题定位到-哪一层" aria-label="Permalink to “6. 常见排错速查（把问题定位到“哪一层”）”">​</a></h2><p>当你遇到“服务起不来/访问不了/数据不对”，优先按层排查：</p><h3 id="_6-1-端口-访问失败" tabindex="-1">6.1 端口/访问失败 <a class="header-anchor" href="#_6-1-端口-访问失败" aria-label="Permalink to “6.1 端口/访问失败”">​</a></h3><ul><li>先确认容器内部是否监听目标端口</li><li>再检查宿主机端口映射是否正确（<code>docker ps</code> / Compose 的 <code>ports</code>）</li><li>检查是否被防火墙或网关拦截（本地开发一般不会，但线上会）</li></ul><h3 id="_6-2-容器启动失败" tabindex="-1">6.2 容器启动失败 <a class="header-anchor" href="#_6-2-容器启动失败" aria-label="Permalink to “6.2 容器启动失败”">​</a></h3><ul><li>优先看日志： <ul><li><code>docker logs &lt;container&gt;</code></li></ul></li><li>再看容器状态（停止/退出码）： <ul><li><code>docker ps -a</code></li></ul></li></ul><h3 id="_6-3-容器间通信失败" tabindex="-1">6.3 容器间通信失败 <a class="header-anchor" href="#_6-3-容器间通信失败" aria-label="Permalink to “6.3 容器间通信失败”">​</a></h3><ul><li>Compose 场景下优先检查： <ul><li>服务名是否正确（用 Compose 服务名访问）</li><li>环境变量/连接串是否一致（例如数据库地址、端口、账号）</li></ul></li></ul><hr><h2 id="_7-交付物建议-放到你的项目仓库-笔记" tabindex="-1">7. 交付物建议（放到你的项目仓库/笔记） <a class="header-anchor" href="#_7-交付物建议-放到你的项目仓库-笔记" aria-label="Permalink to “7. 交付物建议（放到你的项目仓库/笔记）”">​</a></h2><p>为了让 Docker 学习“能用”，建议每个阶段都产出可复现的文件：</p><ul><li><code>Dockerfile</code>：镜像构建脚本</li><li><code>compose.yaml</code> / <code>docker-compose.yml</code>：多服务编排</li><li><code>README.md</code>：包含启动命令、端口、环境变量说明、数据卷说明</li></ul><hr><p>如果你希望我把这一页进一步“落到你的项目模板”，你告诉我你主要用的技术栈（Java/Node/Python）和是否需要数据库（MySQL/PostgreSQL/无），我可以直接给出一个 <code>Dockerfile + Compose + README</code> 的建议骨架。</p>`,99)])])}const u=l(s,[["render",r]]);export{p as __pageData,u as default};
